import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge case: empty quote ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Single-item base premiums + processing fee ---
  it("quote with a single plain sword → premium 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it.todo("quote with a single plain amulet → premium 65 G (60 base + 5 fee)");
  it.todo("quote with a single plain staff → premium 85 G (80 base + 5 fee)");
  it.todo("quote with a single plain potion → premium 45 G (40 base + 5 fee)");

  // --- Components ---
  it.todo("quote with a single rune → premium 30 G (25 base + 5 fee)");
  it.todo("quote with 2 runes → 50 G base + 5 fee = 55 G");
  it.todo("quote with 3 runes (block) → 60 G base + 5 fee = 65 G");
  it.todo("quote with 4 runes → 100 G base + 5 fee = 105 G (no block — block requires exactly 3)");
  it.todo("quote with 7 runes → 175 G base + 5 fee = 180 G");

  // --- 'Alike' clarification ---
  it.todo("quote with 2 runes + 1 moonstone → 75 G base + 5 fee = 80 G (no block — different types)");
  it.todo("quote with 3 runes + 3 moonstones → 120 G base + 5 fee = 125 G (two separate blocks)");

  // --- Item-specific modifiers in isolation ---
  it.todo("cursed sword (no other modifiers) → 100 base + 50 curse + 5 fee = 155 G");
  it.todo("sword with enchantment 5 → 100 base + 30 high-enchantment + 5 fee = 135 G");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge → 105 G");
  it.todo("cursed sword with enchantment 5 → both surcharges → 100 + 50 + 30 + 5 = 185 G");

  // --- Policy-wide modifiers in isolation ---
  it.todo("loyalty discount: 2-year customer, plain sword → 100 − 20 + 5 = 85 G");
  it.todo("first insurance surcharge: 0-year, plain sword (first quote) → 100 + 10 + 5 = 115 G");
  it.todo("follow-up contract discount: second quote in scenario, plain sword (0-year) → 100 + 10 − 15 + 5 = 100 G");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet → policy 160 G base + 50 curse = 210 + 5 fee = 215 G");

  // --- Rounding ---
  it.todo("premium calculation yielding 197.5 G → final 198 G (rounded up in MHPCO's favor)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (0 yrs, enchantment 3) → 165 G");
  it.todo("long-standing customer's second quote: cursed sword enchantment 7 (3 yrs) → 160 G");

  // --- Error handling for quote ---
  it.todo("quote with unknown item type (e.g. broomstick) → throws error");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G");
  it.todo("rune damaged 200 G → payout 100 G (no special clauses; deductible applies)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible applied per item)");

  // --- Claim: special clauses ---
  it.todo("dragon-material sword enchantment 8, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
  it.todo("dragon-material sword enchantment 5, damage 800 G → payout 700 G (full dragon reimbursement minus deductible)");
  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (high-enchantment 50% then deductible)");

  // --- Claim: cap ---
  it.todo("policy with sword and amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (insurance value 1000 G, modified premium 165 G) → cap 2000 G (premium modifiers don't raise cap)");
  it.todo("policy with sword and 3 runes (block) → insurance sum 1750 G (block discount doesn't affect insurance sum)");

  // --- Cap exhaustion across successive claims ---
  it.todo("sword (cap 2000 G), two successive claims of 1500 G each → 1st payout 1400, remaining 600; 2nd payout 600, remaining 0");

  // --- Multiple items of same type ---
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack damages both swords (two sword damages) → each treated as separate damage with its own deductible");

  // --- Claim error handling ---
  it.todo("damages contains more entries of a type than insured → claim rejected (error)");
  it.todo("claim references item not in policy → error");
  it.todo("claim damage entry with negative amount → error");

  // --- Payout rounding ---
  it.todo("payout calculation yielding 350.5 G → final 350 G (rounded down in MHPCO's favor)");
});

