const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const componentGroupTotal = (count: number, unitPrice: number): number =>
  count === BLOCK_SIZE ? BLOCK_PRICE : count * unitPrice;

const sumBasePremiums = (items: Item[]): number => {
  const counts = new Map<string, number>();
  let nonComponentTotal = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    } else {
      nonComponentTotal += basePremium(item);
    }
  }
  let componentsTotal = 0;
  for (const [type, count] of counts) {
    componentsTotal += componentGroupTotal(count, BASE_PREMIUMS[type] ?? 0);
  }
  return nonComponentTotal + componentsTotal;
};

