export type Item = { type: string };

export type QuoteStep = { op: "quote"; items: Item[] };

export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };

export type ScenarioResult = {
  results: QuoteResult[];
};

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const unitPrice = (type: string): number => BASE_PREMIUMS[type] ?? 0;

const countsByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>()
  );

const groupTotal = (type: string, count: number): number =>
  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
    ? BLOCK_PRICE
    : count * unitPrice(type);

const sumBasePremiums = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countsByType(items)) {
    total += groupTotal(type, count);
  }
  return total;
};

const quote = ({ items }: QuoteStep): QuoteResult => ({
  premium: sumBasePremiums(items) + PROCESSING_FEE,
});

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map(quote),
});

