export type Item = {
  type: string;
  cursed?: boolean;
  enchantment?: number;
};

export type QuoteStep = { op: "quote"; items: Item[] };

export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };

export type ScenarioResult = {
  results: QuoteResult[];
};

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const LOYALTY_YEARS_THRESHOLD = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;
const FIRST_INSURANCE_RATE = 0.1;

const unitPrice = (type: string): number => BASE_PREMIUMS[type] ?? 0;

const countsByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>()
  );

const groupTotal = (type: string, count: number): number =>
  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
    ? BLOCK_PRICE
    : count * unitPrice(type);

const sumBasePremiums = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countsByType(items)) {
    total += groupTotal(type, count);
  }
  return total;
};

const itemSurcharges = (item: Item): number => {
  const base = unitPrice(item.type);
  let surcharge = 0;
  if (item.cursed) surcharge += base * 0.5;
  if ((item.enchantment ?? 0) >= 5) surcharge += base * 0.3;
  return surcharge;
};

const sumItemSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemSurcharges(item), 0);

const loyaltyDiscount = (
  basePremiums: number,
  customer: { yearsWithMHPCO: number }
): number =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
    ? basePremiums * LOYALTY_DISCOUNT_RATE
    : 0;

const quote = (
  { items }: QuoteStep,
  customer: { yearsWithMHPCO: number }
): QuoteResult => {
  const basePremiums = sumBasePremiums(items);
  return {
    premium:
      basePremiums +
      sumItemSurcharges(items) -
      loyaltyDiscount(basePremiums, customer) +
      PROCESSING_FEE,
  };
};

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map((step) => quote(step, scenario.customer)),
});

