151	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
152	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
153	    : damage.amount;
154	
155	const damagePayout = (damage: Damage, item: Item): number =>
156	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
157	
158	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
159	  damages.reduce((sum, d) => {
160	    const item = items.find((i) => i.type === d.itemType);
161	    if (!item) throw new Error(`Item ${d.itemType} not in policy`);
162	    return sum + damagePayout(d, item);
163	  }, 0);
164	
165	const validateDamageAmounts = (damages: Damage[]): void => {
166	  const negative = damages.find((d) => d.amount < 0);
167	  if (negative) throw new Error(`Damage amount cannot be negative: ${negative.amount}`);
168	};
169	
170	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
171	  const itemCounts = countBy(items, (item) => item.type);
172	  countBy(damages, (d) => d.itemType).forEach((count, type) => {
173	    if (count > (itemCounts.get(type) ?? 0)) {
174	      throw new Error(`Too many damages for item type ${type}`);
175	    }
176	  });
177	};
178	
179	const claim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
180	  const policy = policies.get(step.policy);
181	  if (!policy) throw new Error(`Policy ${step.policy} not found`);
182	  validateDamageAmounts(step.incident.damages);
183	  validateDamageCounts(step.incident.damages, policy.items);
184	  const desired = sumDamagePayouts(step.incident.damages, policy.items);
185	  const payout = Math.min(desired, policy.remainingCap);
186	  policy.remainingCap -= payout;
187	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
188	};
189	
190	export const runScenario = (scenario: Scenario): ScenarioResult => {
191	  const policies = new Map<number, Policy>();
192	  let quoteIndex = 0;
193	  const results: StepResult[] = scenario.steps.map((step, index) => {
194	    if (step.op === "quote") {
195	      policies.set(index, createPolicy(step.items));
196	      const result = quote(step, scenario.customer, quoteIndex);
197	      quoteIndex++;
198	      return result;
199	    }
200	    return claim(step, policies);
201	  });
202	  return { results };
203	};

